    public init?(rawValue: Int) {
      switch rawValue {
      case 0: self = .unspecifiedSuffix
      case 1: self = .namespace
      case 2: self = .type
      case 3: self = .term
      case 4: self = .method
      case 5: self = .typeParameter
      case 6: self = .parameter
      case 7: self = .meta
      case 8: self = .local
      case 9: self = .macro
      default: self = .UNRECOGNIZED(rawValue)
      }
