      switch self {
      case .unspecifiedSuffix: return 0
      case .namespace: return 1
      case .type: return 2
      case .term: return 3
      case .method: return 4
      case .typeParameter: return 5
      case .parameter: return 6
      case .meta: return 7
      case .local: return 8
      case .macro: return 9
      case .UNRECOGNIZED(let i): return i
